import { BehaviorSubject } from "rxjs";
import { toast } from "react-toastify";
import { Api } from "@lakefusion/utility-portal";

const { middleLayerServiceApi } = Api;

// Types
export interface LogFileInfo {
  filename: string;
  date: string;
  size_bytes: number;
  service: string;
}

export interface LogContentResponse {
  service: string;
  filename: string;
  total_lines: number;
  offset: number;
  limit: number;
  has_more: boolean;
  content: string;
}

export interface ConsoleLogState {
  // Services
  availableServices: string[];
  selectedServices: string[];
  loadingServices: boolean;

  // View panel (only updated on "Fetch Logs" click)
  viewServices: string[];  // Services available in the view dropdown
  availableFiles: LogFileInfo[];
  selectedViewService: string;
  selectedFile: string;
  loadingFiles: boolean;

  // Content
  logContent: string;
  totalLines: number;
  loadingContent: boolean;

  // Date range
  startDate: string;
  endDate: string;

  // Export
  isExporting: boolean;
}

// Helper to format date for input
const formatDateForInput = (date: Date) => {
  return date.toISOString().split('T')[0];
};

// Initial state
const today = new Date();
const weekAgo = new Date(today);
weekAgo.setDate(weekAgo.getDate() - 7);

export const initialState: ConsoleLogState = {
  availableServices: [],
  selectedServices: [],
  loadingServices: false,

  viewServices: [],
  availableFiles: [],
  selectedViewService: "",
  selectedFile: "",
  loadingFiles: false,

  logContent: "",
  totalLines: 0,
  loadingContent: false,

  startDate: formatDateForInput(weekAgo),
  endDate: formatDateForInput(today),

  isExporting: false,
};

let state = { ...initialState };
export const subject = new BehaviorSubject<ConsoleLogState>(state);

const updateState = (newState: Partial<ConsoleLogState>) => {
  state = {
    ...state,
    ...newState,
  };
  subject.next(state);
};

// Fetch available services
export const fetchServices = async () => {
  updateState({ loadingServices: true });
  try {
    const services = await middleLayerServiceApi.getApi("logs/services", {}, false, {}, false);
    if (services && Array.isArray(services) && services.length > 0) {
      updateState({
        availableServices: services,
        selectedServices: services,
        loadingServices: false,
      });
    } else {
      toast.warning("No log services found. Check if services are logging to the expected location.");
      updateState({
        availableServices: [],
        selectedServices: [],
        loadingServices: false,
      });
    }
  } catch (error: any) {
    console.error('Error fetching services:', error);
    toast.error(`Failed to fetch services: ${error?.message || error}`);
    updateState({
      availableServices: [],
      selectedServices: [],
      loadingServices: false,
    });
  }
};

// Fetch log files - called when "Fetch Logs" is clicked
export const fetchLogs = async () => {
  if (state.selectedServices.length === 0) {
    return;
  }

  // Snapshot the selected services for the view panel
  const viewServices = [...state.selectedServices];
  // Always select the first service
  const firstService = viewServices[0];

  // Reset everything and set first service as selected
  updateState({
    loadingFiles: true,
    viewServices,
    selectedViewService: firstService,
    availableFiles: [],
    selectedFile: "",
    logContent: "",
    totalLines: 0,
  });

  // Fetch files for the first service
  await fetchFilesForServiceInternal(firstService);
};

// Internal function to fetch files for a specific service
const fetchFilesForServiceInternal = async (service: string) => {
  try {
    const files = await middleLayerServiceApi.getApi(
      "logs/files?",
      { service, start_date: state.startDate, end_date: state.endDate },
      false,
      {},
      false
    );
    if (files && Array.isArray(files) && files.length > 0) {
      updateState({
        availableFiles: files,
        selectedFile: files[0].filename,
        loadingFiles: false,
      });
    } else {
      toast.info(`No log files found for ${service} in the selected date range.`);
      updateState({
        availableFiles: [],
        selectedFile: "",
        loadingFiles: false,
      });
    }
  } catch (error: any) {
    console.error('Error fetching files:', error);
    toast.error(`Failed to fetch log files: ${error?.message || error}`);
    updateState({
      availableFiles: [],
      selectedFile: "",
      loadingFiles: false,
    });
  }
};

// Fetch files when user changes the view service dropdown
export const fetchFilesForService = async (service: string) => {
  updateState({
    loadingFiles: true,
    selectedViewService: service,
    availableFiles: [],
    selectedFile: "",
    logContent: "",
    totalLines: 0,
  });
  await fetchFilesForServiceInternal(service);
};

// Fetch log content
export const fetchLogContent = async () => {
  if (!state.selectedViewService || !state.selectedFile) {
    return;
  }

  updateState({ loadingContent: true });
  try {
    const data = await middleLayerServiceApi.getApi(
      "logs/content?",
      { service: state.selectedViewService, filename: state.selectedFile, limit: "5000" },
      false,
      {},
      false
    );
    if (data && data.content) {
      updateState({
        logContent: data.content,
        totalLines: data.total_lines,
        loadingContent: false,
      });
    } else {
      toast.info("Log file is empty.");
      updateState({
        logContent: "",
        totalLines: 0,
        loadingContent: false,
      });
    }
  } catch (error: any) {
    console.error('Error fetching log content:', error);
    toast.error(`Failed to fetch log content: ${error?.message || error}`);
    updateState({
      logContent: "",
      totalLines: 0,
      loadingContent: false,
    });
  }
};

// Export logs
export const exportLogs = async () => {
  if (state.selectedServices.length === 0) {
    toast.warning('Please select at least one service');
    return;
  }

  updateState({ isExporting: true });
  try {
    const baseUrl = (window as any).env?.MIDDLELAYER_SERVICE_URL || '';
    const token = localStorage.getItem('access_token') || '';

    const response = await fetch(`${baseUrl}logs/export`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
      },
      body: JSON.stringify({
        services: state.selectedServices,
        start_date: state.startDate,
        end_date: state.endDate,
      }),
    });

    if (response.ok) {
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `logs_${state.startDate}_to_${state.endDate}.zip`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('Logs exported successfully');
    } else {
      const errorData = await response.json().catch(() => ({}));
      toast.error(errorData.detail || 'Export failed. Please ensure the backend service is running.');
    }
  } catch (error: any) {
    console.error('Error exporting logs:', error);
    toast.error(`Export failed: ${error?.message || error}`);
  } finally {
    updateState({ isExporting: false });
  }
};

// State setters
export const setStartDate = (startDate: string) => {
  updateState({ startDate });
};

export const setEndDate = (endDate: string) => {
  updateState({ endDate });
};

export const setSelectedViewService = (selectedViewService: string) => {
  // Only update the selected service, don't reset files/content
  // Reset only happens when "Fetch Logs" is clicked
  updateState({ selectedViewService });
};

export const setSelectedFile = (selectedFile: string) => {
  updateState({ selectedFile });
};

export const toggleService = (service: string) => {
  const currentServices = state.selectedServices;
  const newServices = currentServices.includes(service)
    ? currentServices.filter(s => s !== service)
    : [...currentServices, service];
  updateState({ selectedServices: newServices });
};

export const selectAllServices = () => {
  updateState({ selectedServices: [...state.availableServices] });
};

export const deselectAllServices = () => {
  updateState({ selectedServices: [] });
};

// Reset state
export const resetState = () => {
  state = { ...initialState };
  subject.next(state);
};

// Get current state (for non-reactive access)
export const getState = () => state;
