import React, { useState, useMemo, useRef, useEffect } from "react";
import {
  RevampedPageLayout,
  ShadComponents,
} from "@lakefusion/utility-portal";
import {
  Search,
  RefreshCw,
  Download,
  Filter,
  ChevronDown,
  X,
  ScrollText,
  Terminal,
  Calendar,
  Loader2,
  Server,
  FileText,
} from "lucide-react";
import {
  subject,
  fetchServices,
  fetchLogs,
  fetchFilesForService,
  fetchLogContent,
  exportLogs,
  setStartDate,
  setEndDate,
  setSelectedFile,
  toggleService,
  selectAllServices,
  deselectAllServices,
  ConsoleLogState,
  LogFileInfo,
} from "./consoleLogService";

const {
  Button,
  Input,
  Select,
  SelectTrigger,
  SelectContent,
  SelectItem,
  SelectValue,
  Popover,
  PopoverTrigger,
  PopoverContent,
  Checkbox,
} = ShadComponents;

const logLevels = [
  { value: "all", label: "All Levels" },
  { value: "INFO", label: "INFO" },
  { value: "WARN", label: "WARN" },
  { value: "ERROR", label: "ERROR" },
  { value: "DEBUG", label: "DEBUG" },
];

const getLevelColor = (level: string) => {
  switch (level) {
    case "INFO":
      return "text-blue-400";
    case "WARN":
    case "WARNING":
      return "text-yellow-400";
    case "ERROR":
      return "text-red-400";
    case "DEBUG":
      return "text-slate-500";
    default:
      return "text-slate-400";
  }
};

const LogLine: React.FC<{ line: string; searchQuery: string }> = ({ line, searchQuery }) => {
  // Parse log line: YYYY-MM-DD HH:MM:SS,mmm - logger - LEVEL - message
  const match = line.match(/^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2},\d{3}) - ([^ ]+) - (INFO|WARN|WARNING|ERROR|DEBUG) - (.*)$/);

  if (!match) {
    return <div className="font-mono text-xs text-slate-400">{line}</div>;
  }

  const [, timestamp, logger, level, message] = match;

  const highlightMatch = (text: string) => {
    if (!searchQuery) return text;
    const regex = new RegExp(`(${searchQuery.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
    const parts = text.split(regex);
    return parts.map((part, i) =>
      regex.test(part) ? (
        <span key={i} className="bg-yellow-500/30 text-yellow-200">{part}</span>
      ) : part
    );
  };

  return (
    <div className="font-mono text-xs leading-5 hover:bg-slate-800/50">
      <span className="text-slate-500">{timestamp}</span>
      <span className="text-slate-600"> - </span>
      <span className="text-cyan-400">{highlightMatch(logger)}</span>
      <span className="text-slate-600"> - </span>
      <span className={`font-semibold ${getLevelColor(level)}`}>{level}</span>
      <span className="text-slate-600"> - </span>
      <span className="text-slate-300">{highlightMatch(message)}</span>
    </div>
  );
};

// Helper to format bytes
const formatBytes = (bytes: number) => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

export const ConsoleLogViewer: React.FC = () => {
  // Subscribe to service state
  const [state, setState] = useState<ConsoleLogState>(subject.getValue());

  // Local UI state (not in service)
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedLevel, setSelectedLevel] = useState("all");
  const [showFilters, setShowFilters] = useState(false);

  const logContainerRef = useRef<HTMLDivElement>(null);

  // Subscribe to service state changes
  useEffect(() => {
    const subscription = subject.subscribe(setState);
    return () => subscription.unsubscribe();
  }, []);

  // Fetch available services on mount
  useEffect(() => {
    fetchServices();
  }, []);

  // Fetch content when file changes
  useEffect(() => {
    if (state.selectedViewService && state.selectedFile) {
      fetchLogContent();
    }
  }, [state.selectedViewService, state.selectedFile]);

  const handleRefresh = () => {
    if (state.selectedViewService && state.selectedFile) {
      fetchLogContent();
    }
  };

  const handleFetchLogs = () => {
    if (state.selectedServices.length > 0) {
      fetchLogs();
    }
  };

  const filteredLines = useMemo(() => {
    if (!state.logContent) return [];

    const lines = state.logContent.split('\n').filter(line => line.trim());

    return lines.filter(line => {
      // Filter by search query
      if (searchQuery && !line.toLowerCase().includes(searchQuery.toLowerCase())) {
        return false;
      }

      // Filter by level
      if (selectedLevel !== "all") {
        const levelMatch = line.match(/ - (INFO|WARN|WARNING|ERROR|DEBUG) - /);
        if (!levelMatch || levelMatch[1] !== selectedLevel) {
          return false;
        }
      }

      return true;
    });
  }, [state.logContent, searchQuery, selectedLevel]);

  const clearFilters = () => {
    setSearchQuery("");
    setSelectedLevel("all");
  };

  const hasActiveFilters = selectedLevel !== "all";

  // View service dropdown uses the services that were selected when "Fetch Logs" was clicked
  const viewServiceOptions = state.viewServices;

  return (
    <RevampedPageLayout>
      <div className="border border-slate-200 rounded-lg bg-white overflow-hidden flex flex-col h-full">
        {/* Header Section */}
        <div className="p-4 bg-slate-50/50 border-b border-slate-200 shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-amber-100 flex items-center justify-center">
              <ScrollText className="w-5 h-5 text-amber-600" />
            </div>
            <div>
              <h1 className="text-lg font-semibold text-slate-800">Console Log Viewer</h1>
              <p className="text-sm text-slate-500">Browse and search application logs across all services.</p>
            </div>
          </div>
        </div>

        {/* Filter Controls - Date Range & Services */}
        <div className="p-3 border-b border-slate-200 bg-slate-50/30 shrink-0">
          <div className="flex items-center gap-4 flex-wrap">
            {/* Date Range */}
            <div className="flex items-center gap-2 h-8">
              <Calendar className="w-5 h-5 text-slate-500 shrink-0" />
              <span className="text-sm text-slate-600 font-medium whitespace-nowrap">Date Range:</span>
              <Input
                type="date"
                value={state.startDate}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setStartDate(e.target.value)}
                height="h-8"
                className="w-[140px] text-sm"
              />
              <span className="text-sm text-slate-500">to</span>
              <Input
                type="date"
                value={state.endDate}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setEndDate(e.target.value)}
                height="h-8"
                className="w-[140px] text-sm"
              />
            </div>

            {/* Services Multi-Select */}
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 gap-2">
                  <Server className="w-4 h-4" />
                  Services
                  {state.selectedServices.length > 0 && (
                    <span className="bg-teal-600 text-white text-xs px-1.5 py-0.5 rounded-full min-w-[20px] text-center">
                      {state.selectedServices.length}
                    </span>
                  )}
                  <ChevronDown className="w-3 h-3" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-72 p-0" align="start">
                {/* Header */}
                <div className="flex items-center justify-between px-4 py-3 border-b border-slate-100 bg-slate-50/50">
                  <div className="flex items-center gap-2">
                    <Server className="w-4 h-4 text-slate-500" />
                    <span className="text-sm font-semibold text-slate-700">Select Services</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <button
                      className="text-xs px-2 py-1 rounded hover:bg-teal-50 text-teal-600 font-medium transition-colors"
                      onClick={selectAllServices}
                    >
                      All
                    </button>
                    <span className="text-slate-300">|</span>
                    <button
                      className="text-xs px-2 py-1 rounded hover:bg-slate-100 text-slate-500 font-medium transition-colors"
                      onClick={deselectAllServices}
                    >
                      None
                    </button>
                  </div>
                </div>
                {/* Service List */}
                <div className="max-h-64 overflow-auto p-2">
                  {state.loadingServices ? (
                    <div className="flex items-center justify-center py-6">
                      <Loader2 className="w-5 h-5 animate-spin text-slate-400" />
                    </div>
                  ) : (
                    <div className="space-y-1">
                      {state.availableServices.map((service, index) => {
                        const isChecked = state.selectedServices.includes(service);
                        const serviceColors = [
                          "bg-blue-500",
                          "bg-purple-500",
                          "bg-teal-500",
                          "bg-orange-500",
                          "bg-pink-500",
                          "bg-cyan-500",
                        ];
                        const colorClass = serviceColors[index % serviceColors.length];

                        return (
                          <label
                            key={service}
                            htmlFor={service}
                            className={`flex items-center gap-3 px-3 py-2.5 rounded-lg cursor-pointer transition-all ${
                              isChecked
                                ? "bg-teal-50 border border-teal-200"
                                : "hover:bg-slate-50 border border-transparent"
                            }`}
                          >
                            <Checkbox
                              id={service}
                              checked={isChecked}
                              onCheckedChange={() => toggleService(service)}
                              className="data-[state=checked]:bg-teal-600 data-[state=checked]:border-teal-600"
                            />
                            <div className={`w-2 h-2 rounded-full ${colorClass}`} />
                            <span className={`text-sm ${isChecked ? "text-slate-800 font-medium" : "text-slate-600"}`}>
                              {service.replace(/_/g, " ").replace(/-/g, " ")}
                            </span>
                          </label>
                        );
                      })}
                    </div>
                  )}
                </div>
                {/* Footer */}
                <div className="px-4 py-2 border-t border-slate-100 bg-slate-50/30">
                  <p className="text-xs text-slate-400">
                    {state.selectedServices.length} of {state.availableServices.length} selected
                  </p>
                </div>
              </PopoverContent>
            </Popover>

            {/* Fetch Button */}
            <Button
              size="sm"
              className="h-8 gap-2 bg-teal-600 hover:bg-teal-700 text-white"
              onClick={handleFetchLogs}
              disabled={state.loadingFiles || state.selectedServices.length === 0}
            >
              {state.loadingFiles ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Search className="w-4 h-4" />
              )}
              Fetch Logs
            </Button>

            <div className="flex-1" />

            {/* Export Button */}
            <Button
              size="sm"
              className="h-8 gap-2 bg-primary hover:bg-primary/90 text-white"
              onClick={exportLogs}
              disabled={state.isExporting || state.selectedServices.length === 0}
            >
              {state.isExporting ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Download className="w-4 h-4" />
              )}
              Export ({state.selectedServices.length} services)
            </Button>
          </div>
        </div>

        {/* View Controls */}
        <div className="p-3 border-b border-slate-100 flex items-center gap-3 shrink-0 flex-wrap">
          {/* View Service Selector */}
          <div className="flex items-center gap-2 h-8">
            <Server className="w-4 h-4 text-slate-500 shrink-0" />
            <Select
              value={state.selectedViewService || ""}
              onValueChange={(v: string) => fetchFilesForService(v)}
            >
              <SelectTrigger className="h-8 w-[180px] text-sm">
                {state.selectedViewService ? (
                  <SelectValue />
                ) : (
                  <span className="text-muted-foreground">Select service</span>
                )}
              </SelectTrigger>
              <SelectContent>
                {viewServiceOptions.map((service) => (
                  <SelectItem key={service} value={service} className="text-sm">
                    {service}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Log File Selector */}
          <div className="flex items-center gap-2 h-8">
            <FileText className="w-4 h-4 text-slate-500 shrink-0" />
            <Select value={state.selectedFile || ""} onValueChange={(v: string) => setSelectedFile(v)} disabled={state.loadingFiles}>
              <SelectTrigger className="h-8 w-[220px] text-sm">
                {state.loadingFiles ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : state.selectedFile ? (
                  <SelectValue />
                ) : (
                  <span className="text-muted-foreground">Select log file</span>
                )}
              </SelectTrigger>
              <SelectContent>
                {state.availableFiles.map((file: LogFileInfo) => (
                  <SelectItem key={file.filename} value={file.filename} className="text-sm">
                    <span>{file.filename}</span>
                    <span className="text-slate-400 ml-2">({formatBytes(file.size_bytes)})</span>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Search */}
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 z-10" />
            <Input
              placeholder="Search logs..."
              value={searchQuery}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setSearchQuery(e.target.value)}
              height="h-8"
              className="pl-9 text-sm w-full"
            />
          </div>

          {/* Level Filter */}
          <Button
            variant="outline"
            size="sm"
            className={`h-8 gap-2 ${showFilters || hasActiveFilters ? "border-violet-500 bg-violet-50 text-violet-700 hover:bg-violet-100" : ""}`}
            onClick={() => setShowFilters(!showFilters)}
          >
            <Filter className="w-4 h-4" />
            Level
            {hasActiveFilters && (
              <span className="bg-violet-600 text-white text-xs px-1.5 py-0.5 rounded-full">1</span>
            )}
          </Button>

          <Button
            size="sm"
            className="h-8 gap-2 bg-teal-600 text-white hover:bg-teal-700"
            onClick={handleRefresh}
            disabled={state.loadingContent || !state.selectedFile}
          >
            <RefreshCw className={`w-4 h-4 ${state.loadingContent ? "animate-spin" : ""}`} />
            Refresh
          </Button>
        </div>

        {/* Filter Options */}
        {showFilters && (
          <div className="px-3 py-2 border-b border-slate-100 bg-slate-50/30 flex flex-wrap items-center gap-4 shrink-0">
            <div className="flex items-center gap-2">
              <span className="text-xs text-slate-500">Log Level:</span>
              <Select value={selectedLevel} onValueChange={setSelectedLevel}>
                <SelectTrigger className="h-7 w-[120px] text-xs">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {logLevels.map((level) => (
                    <SelectItem key={level.value} value={level.value} className="text-xs">
                      {level.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            {hasActiveFilters && (
              <Button
                variant="ghost"
                size="sm"
                className="h-7 text-xs text-slate-500 hover:text-slate-700"
                onClick={clearFilters}
              >
                <X className="w-3 h-3 mr-1" />
                Clear filters
              </Button>
            )}
          </div>
        )}

        {/* Log Content - Terminal Style */}
        <div
          ref={logContainerRef}
          className="flex-1 overflow-auto bg-slate-900 p-4"
        >
          {state.loadingContent ? (
            <div className="flex items-center justify-center h-full">
              <div className="text-center">
                <Loader2 className="mx-auto h-8 w-8 text-slate-500 animate-spin" />
                <p className="mt-2 text-sm text-slate-400">Loading logs...</p>
              </div>
            </div>
          ) : filteredLines.length > 0 ? (
            <div className="space-y-0.5">
              {filteredLines.map((line, idx) => (
                <LogLine key={idx} line={line} searchQuery={searchQuery} />
              ))}
            </div>
          ) : (
            <div className="flex items-center justify-center h-full">
              <div className="text-center">
                <Terminal className="mx-auto h-12 w-12 text-slate-600" />
                <h3 className="mt-2 text-sm font-medium text-slate-400">
                  {!state.selectedFile ? "No log file selected" : "No logs found"}
                </h3>
                <p className="mt-1 text-xs text-slate-500">
                  {!state.selectedFile
                    ? "Select a service and log file to view logs"
                    : searchQuery || hasActiveFilters
                    ? "Try adjusting your search or filter criteria"
                    : "The selected log file is empty"}
                </p>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-3 py-2 border-t border-slate-200 bg-slate-50 shrink-0 flex items-center justify-between">
          <div className="text-xs text-slate-500">
            Showing <span className="font-medium text-slate-700">{filteredLines.length}</span>
            {state.totalLines > 0 && (
              <span> of {state.totalLines}</span>
            )} lines
            {(searchQuery || hasActiveFilters) && (
              <span> (filtered)</span>
            )}
          </div>
          <div className="text-xs text-slate-400">
            {state.selectedViewService && state.selectedFile ? `${state.selectedViewService} / ${state.selectedFile}` : "No file selected"}
          </div>
        </div>
      </div>
    </RevampedPageLayout>
  );
};

export default ConsoleLogViewer;
